mapper.select:
SELECT o.id, o.outbound_no, o.sales_order_id, o.grain_id, o.position_id, o.plan_weight, o.actual_weight, o.deviation_rate, o.outbound_type, o.outbound_reason, o.attachment_url, o.batch_no, o.status, o.confirm_user_id, o.confirm_time, o.create_user_id, o.create_time, g.grain_type, g.grain_grade, s.position_name, CASE o.status WHEN 0 THEN '待确认' WHEN 1 THEN '执行中' WHEN 2 THEN '已完成' WHEN 3 THEN '已作废' ELSE '未知' END AS status_name, CASE o.outbound_type WHEN 0 THEN '销售出库' WHEN 1 THEN '调拨出库' WHEN 2 THEN '应急出库' ELSE '未知' END AS outbound_type_name FROM t_outbound_order o LEFT JOIN t_grain g ON o.grain_id = g.id LEFT JOIN t_storage_position s ON o.position_id = s.id WHERE 1=1
AND o.grain_id = #{grainId}
AND o.position_id = #{positionId}
AND DATE(o.create_time) >= #{dateFrom}
AND DATE(o.create_time) <= #{dateTo}
AND o.status = #{status}
ORDER BY o.create_time DESC
